using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        // Seed roles
        builder.Entity<IdentityRole>().HasData(
            new IdentityRole { Id = "dispatcher-role-id", Name = "Dispatcher", NormalizedName = "DISPATCHER" },
            new IdentityRole { Id = "customer-role-id", Name = "Customer", NormalizedName = "CUSTOMER" }
        );

        // Seed sample shipments
        builder.Entity<Shipment>().HasData(
            new Shipment
            {
                Id = 1,
                TrackingNumber = "TRK-001",
                Origin = "New York, NY",
                Destination = "Los Angeles, CA",
