@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Manage Shipments</PageTitle>

<h1>Manage Shipments</h1>

<button class="btn btn-success mb-3" @onclick="ShowCreateForm">+ New Shipment</button>

@if (showForm)
{
    <div class="card mb-3 p-3">
        <h4>Create Shipment</h4>
        <div class="row g-2">
            <div class="col-md-3">
                <input class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
            </div>
            <div class="col-md-2">
                <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
            </div>
            <div class="col-md-2">
                <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
            </div>
            <div class="col-md-2">
                <input class="form-control" placeholder="Recipient" @bind="newShipment.RecipientName" />
            </div>
            <div class="col-md-2">
                <input class="form-control" type="date" @bind="estimatedDelivery" />
            </div>
            <div class="col-md-1">
                <button class="btn btn-primary" @onclick="CreateShipment">Save</button>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Recipient</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in shipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>@s.RecipientName</td>
                    <td>@s.Status</td>
                    <td>@s.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                            @onchange="(e) => UpdateStatus(s.Id, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool showForm;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDelivery;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showForm = !showForm;

    private async Task CreateShipment()
    {
        newShipment.EstimatedDelivery = estimatedDelivery;
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new();
        estimatedDelivery = null;
        showForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, status);
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
    }
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Customer")]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipments</PageTitle>

<h1>My Shipments</h1>

<div class="mb-3 row">
    <div class="col-md-4">
        <input class="form-control" placeholder="Search by tracking number" @bind="searchTracking" />
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="SearchByTracking">Search</button>
    </div>
</div>

@if (searchResult is not null)
{
    <div class="card mb-3 p-3">
        <h5>Search Result</h5>
        <p><strong>Tracking #:</strong> @searchResult.TrackingNumber</p>
        <p><strong>Status:</strong> @searchResult.Status</p>
